# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, id, balance=0):
        self.id = id
        self.balance = balance
        
    def process_transactions(self, filename):
        with open(filename) as file:
            for line in file:
                transaction = line.strip().split()
                
                if len(transaction) != 2 or not transaction[0].isdigit():
                    print("Invalid transaction format")
                    continue
                    
                amount = int(transaction[1])
                
                if self.id == transaction[0]:
                    self.balance += amount
                else:
                    print(f"Transaction denied for account {self.id}.")